{"type":"user","message":{"role":"user","content":[{"tool_use_id":"967590760","type":"tool_result","content":"1\t/**\n2\t * @module\n3\t * This module is the base module for the Hono object.\n4\t */\n5\t\n6\t/* eslint-disable @typescript-eslint/no-explicit-any */\n7\timport { compose } from './compose'\n8\timport { Context } from './context'\n9\timport type { ExecutionContext } from './context'\n10\timport type { Router } from './router'\n11\timport { METHODS, METHOD_NAME_ALL, METHOD_NAME_ALL_LOWERCASE } from './router'\n12\timport type {\n13\t  Env,\n14\t  ErrorHandler,\n15\t  FetchEventLike,\n16\t  H,\n17\t  HandlerInterface,\n18\t  MergePath,\n19\t  MergeSchemaPath,\n20\t  MiddlewareHandler,\n21\t  MiddlewareHandlerInterface,\n22\t  Next,\n23\t  NotFoundHandler,\n24\t  OnHandlerInterface,\n25\t  RouterRoute,\n26\t  Schema,\n27\t} from './types'\n28\timport { COMPOSED_HANDLER } from './utils/constants'\n29\timport { getPath, getPathNoStrict, mergePath } from './utils/url'\n30\t\n31\tconst notFoundHandler: NotFoundHandler = (c) => {\n32\t  return c.text('404 Not Found', 404)\n33\t}\n34\t\n35\tconst errorHandler: ErrorHandler = (err, c) => {\n36\t  if ('getResponse' in err) {\n37\t    const res = err.getResponse()\n38\t    return c.newResponse(res.body, res)\n39\t  }\n40\t  console.error(err)\n41\t  return c.text('Internal Server Error', 500)\n42\t}\n43\t\n44\ttype GetPath<E extends Env> = (request: Request, options?: { env?: E['Bindings'] }) => string\n45\t\n46\texport type HonoOptions<E extends Env> = {\n47\t  /**\n48\t   * `strict` option specifies whether to distinguish whether the last path is a directory or not.\n49\t   *\n50\t   * @see {@link https://hono.dev/docs/api/hono#strict-mode}\n51\t   *\n52\t   * @default true\n53\t   */\n54\t  strict?: boolean\n55\t  /**\n56\t   * `router` option specifies which router to use.\n57\t   *\n58\t   * @see {@link https://hono.dev/docs/api/hono#router-option}\n59\t   *\n60\t   * @example\n61\t   * ```ts\n62\t   * const app = new Hono({ router: new RegExpRouter() })\n63\t   * ```\n64\t   */\n65\t  router?: Router<[H, RouterRoute]>\n66\t  /**\n67\t   * `getPath` can handle the host header value.\n68\t   *\n69\t   * @see {@link https://hono.dev/docs/api/routing#routing-with-host-header-value}\n70\t   *\n71\t   * @example\n72\t   * ```ts\n73\t   * const app = new Hono({\n74\t   *  getPath: (req) =>\n75\t   *   '/' + req.headers.get('host') + req.url.replace(/^https?:\\/\\/[^/]+(\\/[^?]*)/, '$1'),\n76\t   * })\n77\t   *\n78\t   * app.get('/www1.example.com/hello', () => c.text('hello www1'))\n79\t   *\n80\t   * // A following request will match the route:\n81\t   * // new Request('http://www1.example.com/hello', {\n82\t   * //  headers: { host: 'www1.example.com' },\n83\t   * // })\n84\t   * ```\n85\t   */\n86\t  getPath?: GetPath<E>\n87\t}\n88\t\n89\ttype MountOptionHandler = (c: Context) => unknown\n90\ttype MountReplaceRequest = (originalRequest: Request) => Request\n91\ttype MountOptions =\n92\t  | MountOptionHandler\n93\t  | {\n94\t      optionHandler?: MountOptionHandler\n95\t      replaceRequest?: MountReplaceRequest | false\n96\t    }\n97\t\n98\tclass Hono<\n99\t  E extends Env = Env,\n100\t  S extends Schema = {},\n101\t  BasePath extends string = '/',\n102\t  CurrentPath extends string = BasePath,\n103\t> {\n104\t  get!: HandlerInterface<E, 'get', S, BasePath, CurrentPath>\n105\t  post!: HandlerInterface<E, 'post', S, BasePath, CurrentPath>\n106\t  put!: HandlerInterface<E, 'put', S, BasePath, CurrentPath>\n107\t  delete!: HandlerInterface<E, 'delete', S, BasePath, CurrentPath>\n108\t  options!: HandlerInterface<E, 'options', S, BasePath, CurrentPath>\n109\t  patch!: HandlerInterface<E, 'patch', S, BasePath, CurrentPath>\n110\t  all!: HandlerInterface<E, 'all', S, BasePath, CurrentPath>\n111\t  on: OnHandlerInterface<E, S, BasePath>\n112\t  use: MiddlewareHandlerInterface<E, S, BasePath>\n113\t\n114\t  /*\n115\t    This class is like an abstract class and does not have a router.\n116\t    To use it, inherit the class and implement router in the constructor.\n117\t  */\n118\t  router!: Router<[H, RouterRoute]>\n119\t  readonly getPath: GetPath<E>\n120\t  // Cannot use `#` because it requires visibility at JavaScript runtime.\n121\t  private _basePath: string = '/'\n122\t  #path: string = '/'\n123\t\n124\t  routes: RouterRoute[] = []\n125\t\n126\t  constructor(options: HonoOptions<E> = {}) {\n127\t    // Implementation of app.get(...handlers[]) or app.get(path, ...handlers[])\n128\t    const allMethods = [...METHODS, METHOD_NAME_ALL_LOWERCASE]\n129\t    allMethods.forEach((method) => {\n130\t      this[method] = (args1: string | H, ...args: H[]) => {\n131\t        if (typeof args1 === 'string') {\n132\t          this.#path = args1\n133\t        } else {\n134\t          this.#addRoute(method, this.#path, args1)\n135\t        }\n136\t        args.forEach((handler) => {\n137\t          this.#addRoute(method, this.#path, handler)\n138\t        })\n139\t        return this as any\n140\t      }\n141\t    })\n142\t\n143\t    // Implementation of app.on(method, path, ...handlers[])\n144\t    this.on = (method: string | string[], path: string | string[], ...handlers: H[]) => {\n145\t      for (const p of [path].flat()) {\n146\t        this.#path = p\n147\t        for (const m of [method].flat()) {\n148\t          handlers.map((handler) => {\n149\t            this.#addRoute(m.toUpperCase(), this.#path, handler)\n150\t          })\n151\t        }\n152\t      }\n153\t      return this as any\n154\t    }\n155\t\n156\t    // Implementation of app.use(...handlers[]) or app.use(path, ...handlers[])\n157\t    this.use = (arg1: string | MiddlewareHandler<any>, ...handlers: MiddlewareHandler<any>[]) => {\n158\t      if (typeof arg1 === 'string') {\n159\t        this.#path = arg1\n160\t      } else {\n161\t        this.#path = '*'\n162\t        handlers.unshift(arg1)\n163\t      }\n164\t      handlers.forEach((handler) => {\n165\t        this.#addRoute(METHOD_NAME_ALL, this.#path, handler)\n166\t      })\n167\t      return this as any\n168\t    }\n169\t\n170\t    const { strict, ...optionsWithoutStrict } = options\n171\t    Object.assign(this, optionsWithoutStrict)\n172\t    this.getPath = (strict ?? true) ? (options.getPath ?? getPath) : getPathNoStrict\n173\t  }\n174\t\n175\t  #clone(): Hono<E, S, BasePath, CurrentPath> {\n176\t    const clone = new Hono<E, S, BasePath, CurrentPath>({\n177\t      router: this.router,\n178\t      getPath: this.getPath,\n179\t    })\n180\t    clone.errorHandler = this.errorHandler\n181\t    clone.#notFoundHandler = this.#notFoundHandler\n182\t    clone.routes = this.routes\n183\t    return clone\n184\t  }\n185\t\n186\t  #notFoundHandler: NotFoundHandler = notFoundHandler\n187\t  // Cannot use `#` because it requires visibility at JavaScript runtime.\n188\t  private errorHandler: ErrorHandler = errorHandler\n189\t\n190\t  /**\n191\t   * `.route()` allows grouping other Hono instance in routes.\n192\t   *\n193\t   * @see {@link https://hono.dev/docs/api/routing#grouping}\n194\t   *\n195\t   * @param {string} path - base Path\n196\t   * @param {Hono} app - other Hono instance\n197\t   * @returns {Hono} routed Hono instance\n198\t   *\n199\t   * @example\n200\t   * ```ts\n201\t   * const app = new Hono()\n202\t   * const app2 = new Hono()\n203\t   *\n204\t   * app2.get(\"/user\", (c) => c.text(\"user\"))\n205\t   * app.route(\"/api\", app2) // GET /api/user\n206\t   * ```\n207\t   */\n208\t  route<\n209\t    SubPath extends string,\n210\t    SubEnv extends Env,\n211\t    SubSchema extends Schema,\n212\t    SubBasePath extends string,\n213\t    SubCurrentPath extends string,\n214\t  >(\n215\t    path: SubPath,\n216\t    app: Hono<SubEnv, SubSchema, SubBasePath, SubCurrentPath>\n217\t  ): Hono<E, MergeSchemaPath<SubSchema, MergePath<BasePath, SubPath>> | S, BasePath, CurrentPath> {\n218\t    const subApp = this.basePath(path)\n219\t    app.routes.map((r) => {\n220\t      let handler\n221\t      if (app.errorHandler === errorHandler) {\n222\t        handler = r.handler\n223\t      } else {\n224\t        handler = async (c: Context, next: Next) =>\n225\t          (await compose([], app.errorHandler)(c, () => r.handler(c, next))).res\n226\t        ;(handler as any)[COMPOSED_HANDLER] = r.handler\n227\t      }\n228\t\n229\t      subApp.#addRoute(r.method, r.path, handler, r.basePath)\n230\t    })\n231\t    return this\n232\t  }\n233\t\n234\t  /**\n235\t   * `.basePath()` allows base paths to be specified.\n236\t   *\n237\t   * @see {@link https://hono.dev/docs/api/routing#base-path}\n238\t   *\n239\t   * @param {string} path - base Path\n240\t   * @returns {Hono} changed Hono instance\n241\t   *\n242\t   * @example\n243\t   * ```ts\n244\t   * const api = new Hono().basePath('/api')\n245\t   * ```\n246\t   */\n247\t  basePath<SubPath extends string>(\n248\t    path: SubPath\n249\t  ): Hono<E, S, MergePath<BasePath, SubPath>, MergePath<BasePath, SubPath>> {\n250\t    const subApp = this.#clone()\n251\t    subApp._basePath = mergePath(this._basePath, path)\n252\t    return subApp\n253\t  }\n254\t\n255\t  /**\n256\t   * `.onError()` handles an error and returns a customized Response.\n257\t   *\n258\t   * @see {@link https://hono.dev/docs/api/hono#error-handling}\n259\t   *\n260\t   * @param {ErrorHandler} handler - request Handler for error\n261\t   * @returns {Hono} changed Hono instance\n262\t   *\n263\t   * @example\n264\t   * ```ts\n265\t   * app.onError((err, c) => {\n266\t   *   console.error(`${err}`)\n267\t   *   return c.text('Custom Error Message', 500)\n268\t   * })\n269\t   * ```\n270\t   */\n271\t  onError = (handler: ErrorHandler<E>): Hono<E, S, BasePath, CurrentPath> => {\n272\t    this.errorHandler = handler\n273\t    return this\n274\t  }\n275\t\n276\t  /**\n277\t   * `.notFound()` allows you to customize a Not Found Response.\n278\t   *\n279\t   * @see {@link https://hono.dev/docs/api/hono#not-found}\n280\t   *\n281\t   * @param {NotFoundHandler} handler - request handler for not-found\n282\t   * @returns {Hono} changed Hono instance\n283\t   *\n284\t   * @example\n285\t   * ```ts\n286\t   * app.notFound((c) => {\n287\t   *   return c.text('Custom 404 Message', 404)\n288\t   * })\n289\t   * ```\n290\t   */\n291\t  notFound = (handler: NotFoundHandler<E>): Hono<E, S, BasePath, CurrentPath> => {\n292\t    this.#notFoundHandler = handler\n293\t    return this\n294\t  }\n295\t\n296\t  /**\n297\t   * `.mount()` allows you to mount applications built with other frameworks into your Hono application.\n298\t   *\n299\t   * @see {@link https://hono.dev/docs/api/hono#mount}\n300\t   *\n301\t   * @param {string} path - base Path\n302\t   * @param {Function} applicationHandler - other Request Handler\n303\t   * @param {MountOptions} [options] - options of `.mount()`\n304\t   * @returns {Hono} mounted Hono instance\n305\t   *\n306\t   * @example\n307\t   * ```ts\n308\t   * import { Router as IttyRouter } from 'itty-router'\n309\t   * import { Hono } from 'hono'\n310\t   * // Create itty-router application\n311\t   * const ittyRouter = IttyRouter()\n312\t   * // GET /itty-router/hello\n313\t   * ittyRouter.get('/hello', () => new Response('Hello from itty-router'))\n314\t   *\n315\t   * const app = new Hono()\n316\t   * app.mount('/itty-router', ittyRouter.handle)\n317\t   * ```\n318\t   *\n319\t   * @example\n320\t   * ```ts\n321\t   * const app = new Hono()\n322\t   * // Send the request to another application without modification.\n323\t   * app.mount('/app', anotherApp, {\n324\t   *   replaceRequest: (req) => req,\n325\t   * })\n326\t   * ```\n327\t   */\n328\t  mount(\n329\t    path: string,\n330\t    applicationHandler: (request: Request, ...args: any) => Response | Promise<Response>,\n331\t    options?: MountOptions\n332\t  ): Hono<E, S, BasePath, CurrentPath> {\n333\t    // handle options\n334\t    let replaceRequest: MountReplaceRequest | undefined\n335\t    let optionHandler: MountOptionHandler | undefined\n336\t    if (options) {\n337\t      if (typeof options === 'function') {\n338\t        optionHandler = options\n339\t      } else {\n340\t        optionHandler = options.optionHandler\n341\t        if (options.replaceRequest === false) {\n342\t          replaceRequest = (request) => request\n343\t        } else {\n344\t          replaceRequest = options.replaceRequest\n345\t        }\n346\t      }\n347\t    }\n348\t\n349\t    // prepare handlers for request\n350\t    const getOptions: (c: Context) => unknown[] = optionHandler\n351\t      ? (c) => {\n352\t          const options = optionHandler!(c)\n353\t          return Array.isArray(options) ? options : [options]\n354\t        }\n355\t      : (c) => {\n356\t          let executionContext: ExecutionContext | undefined = undefined\n357\t          try {\n358\t            executionContext = c.executionCtx\n359\t          } catch {} // Do nothing\n360\t          return [c.env, executionContext]\n361\t        }\n362\t    replaceRequest ||= (() => {\n363\t      const mergedPath = mergePath(this._basePath, path)\n364\t      const pathPrefixLength = mergedPath === '/' ? 0 : mergedPath.length\n365\t      return (request) => {\n366\t        const url = new URL(request.url)\n367\t        url.pathname = this.getPath(request).slice(pathPrefixLength) || '/'\n368\t        return new Request(url, request)\n369\t      }\n370\t    })()\n371\t\n372\t    const handler: MiddlewareHandler = async (c, next) => {\n373\t      const res = await applicationHandler(replaceRequest(c.req.raw), ...getOptions(c))\n374\t\n375\t      if (res) {\n376\t        return res\n377\t      }\n378\t\n379\t      await next()\n380\t    }\n381\t    this.#addRoute(METHOD_NAME_ALL, mergePath(path, '*'), handler)\n382\t    return this\n383\t  }\n384\t\n385\t  #addRoute(method: string, path: string, handler: H, baseRoutePath?: string): void {\n386\t    method = method.toUpperCase()\n387\t    path = mergePath(this._basePath, path)\n388\t    const r: RouterRoute = {\n389\t      basePath:\n390\t        baseRoutePath !== undefined ? mergePath(this._basePath, baseRoutePath) : this._basePath,\n391\t      path,\n392\t      method,\n393\t      handler,\n394\t    }\n395\t    this.router.add(method, path, [handler, r])\n396\t    this.routes.push(r)\n397\t  }\n398\t\n399\t  #handleError(err: unknown, c: Context<E>): Response | Promise<Response> {\n400\t    if (err instanceof Error) {\n401\t      return this.errorHandler(err, c)\n402\t    }\n403\t    throw err\n404\t  }\n405\t\n406\t  #dispatch(\n407\t    request: Request,\n408\t    executionCtx: ExecutionContext | FetchEventLike | undefined,\n409\t    env: E['Bindings'],\n410\t    method: string\n411\t  ): Response | Promise<Response> {\n412\t    // Handle HEAD method\n413\t    if (method === 'HEAD') {\n414\t      return (async () =>\n415\t        new Response(null, await this.#dispatch(request, executionCtx, env, 'GET')))()\n416\t    }\n417\t\n418\t    const path = this.getPath(request, { env })\n419\t    const matchResult = this.router.match(method, path)\n420\t\n421\t    const c = new Context(request, {\n422\t      path,\n423\t      matchResult,\n424\t      env,\n425\t      executionCtx,\n426\t      notFoundHandler: this.#notFoundHandler,\n427\t    })\n428\t\n429\t    // Do not `compose` if it has only one handler\n430\t    if (matchResult[0].length === 1) {\n431\t      let res: ReturnType<H>\n432\t      try {\n433\t        res = matchResult[0][0][0][0](c, async () => {\n434\t          c.res = await this.#notFoundHandler(c)\n435\t        })\n436\t      } catch (err) {\n437\t        return this.#handleError(err, c)\n438\t      }\n439\t\n440\t      return res instanceof Promise\n441\t        ? res\n442\t            .then(\n443\t              (resolved: Response | undefined) =>\n444\t                resolved || (c.finalized ? c.res : this.#notFoundHandler(c))\n445\t            )\n446\t            .catch((err: Error) => this.#handleError(err, c))\n447\t        : (res ?? this.#notFoundHandler(c))\n448\t    }\n449\t\n450\t    const composed = compose(matchResult[0], this.errorHandler, this.#notFoundHandler)\n451\t\n452\t    return (async () => {\n453\t      try {\n454\t        const context = await composed(c)\n455\t        if (!context.finalized) {\n456\t          throw new Error(\n457\t            'Context is not finalized. Did you forget to return a Response object or `await next()`?'\n458\t          )\n459\t        }\n460\t\n461\t        return context.res\n462\t      } catch (err) {\n463\t        return this.#handleError(err, c)\n464\t      }\n465\t    })()\n466\t  }\n467\t\n468\t  /**\n469\t   * `.fetch()` will be entry point of your app.\n470\t   *\n471\t   * @see {@link https://hono.dev/docs/api/hono#fetch}\n472\t   *\n473\t   * @param {Request} request - request Object of request\n474\t   * @param {Env} Env - env Object\n475\t   * @param {ExecutionContext} - context of execution\n476\t   * @returns {Response | Promise<Response>} response of request\n477\t   *\n478\t   */\n479\t  fetch: (\n480\t    request: Request,\n481\t    Env?: E['Bindings'] | {},\n482\t    executionCtx?: ExecutionContext\n483\t  ) => Response | Promise<Response> = (request, ...rest) => {\n484\t    return this.#dispatch(request, rest[1], rest[0], request.method)\n485\t  }\n486\t\n487\t  /**\n488\t   * `.request()` is a useful method for testing.\n489\t   * You can pass a URL or pathname to send a GET request.\n490\t   * app will return a Response object.\n491\t   * ```ts\n492\t   * test('GET /hello is ok', async () => {\n493\t   *   const res = await app.request('/hello')\n494\t   *   expect(res.status).toBe(200)\n495\t   * })\n496\t   * ```\n497\t   * @see https://hono.dev/docs/api/hono#request\n498\t   */\n499\t  request = (\n500\t    input: Request | string | URL,\n501\t    requestInit?: RequestInit,\n502\t    Env?: E['Bindings'] | {},\n503\t    executionCtx?: ExecutionContext\n504\t  ): Response | Promise<Response> => {\n505\t    if (input instanceof Request) {\n506\t  