ain.js' })\n460\t      expect(res[1][0]).toEqual('main.js')\n461\t      expect(res[1][1]).toEqual({})\n462\t    })\n463\t    it('get /js/chunk/123.js', () => {\n464\t      const [res] = node.search('get', '/js/chunk/123.js')\n465\t      expect(res.length).toBe(1)\n466\t      expect(res[0][0]).toEqual('any file')\n467\t      expect(res[0][1]).toEqual({ filename: 'chunk/123.js' })\n468\t    })\n469\t    it('get /js/chunk/nest/123.js', () => {\n470\t      const [res] = node.search('get', '/js/chunk/nest/123.js')\n471\t      expect(res.length).toBe(1)\n472\t      expect(res[0][0]).toEqual('any file')\n473\t      expect(res[0][1]).toEqual({ filename: 'chunk/nest/123.js' })\n474\t    })\n475\t  })\n476\t  describe('REST API', () => {\n477\t    const node = new Node()\n478\t    node.insert('get', '/users/:username{[a-z]+}', 'profile')\n479\t    node.insert('get', '/users/:username{[a-z]+}/posts', 'posts')\n480\t    it('get /users/hono', () => {\n481\t      const [res] = node.search('get', '/users/hono')\n482\t      expect(res.length).toBe(1)\n483\t      expect(res[0][0]).toEqual('profile')\n484\t    })\n485\t    it('get /users/hono/posts', () => {\n486\t      const [res] = node.search('get', '/users/hono/posts')\n487\t      expect(res.length).toBe(1)\n488\t      expect(res[0][0]).toEqual('posts')\n489\t    })\n490\t  })\n491\t})\n492\t\n493\tdescribe('Duplicate param name', () => {\n494\t  it('self', () => {\n495\t    const node = new Node()\n496\t    node.insert('get', '/:id/:id', 'foo')\n497\t    const [res] = node.search('get', '/123/456')\n498\t    expect(res.length).toBe(1)\n499\t    expect(res[0][0]).toBe('foo')\n500\t    expect(res[0][1]['id']).toBe('123')\n501\t  })\n502\t\n503\t  describe('parent', () => {\n504\t    const node = new Node()\n505\t    node.insert('get', '/:id/:action', 'foo')\n506\t    node.insert('get', '/posts/:id', 'bar')\n507\t    node.insert('get', '/posts/:id/comments/:comment_id', 'comment')\n508\t\n509\t    it('get /123/action', () => {\n510\t      const [res] = node.search('get', '/123/action')\n511\t      expect(res.length).toBe(1)\n512\t      expect(res[0][0]).toBe('foo')\n513\t      expect(res[0][1]).toEqual({ id: '123', action: 'action' })\n514\t    })\n515\t  })\n516\t\n517\t  it('get /posts/456 for comments', () => {\n518\t    const node = new Node()\n519\t    node.insert('get', '/posts/:id/comments/:comment_id', 'comment')\n520\t    const [res] = node.search('get', '/posts/abc/comments/edf')\n521\t    expect(res.length).toBe(1)\n522\t    expect(res[0][0]).toBe('comment')\n523\t    expect(res[0][1]).toEqual({ id: 'abc', comment_id: 'edf' })\n524\t  })\n525\t\n526\t  describe('child', () => {\n527\t    const node = new Node()\n528\t    node.insert('get', '/posts/:id', 'foo')\n529\t    node.insert('get', '/:id/:action', 'bar')\n530\t    it('get /posts/action', () => {\n531\t      const [res] = node.search('get', '/posts/action')\n532\t      expect(res.length).toBe(2)\n533\t      expect(res[0][0]).toBe('foo')\n534\t      expect(res[0][1]).toEqual({ id: 'action' })\n535\t      expect(res[1][0]).toBe('bar')\n536\t      expect(res[1][1]).toEqual({ id: 'posts', action: 'action' })\n537\t    })\n538\t  })\n539\t\n540\t  describe('regular expression', () => {\n541\t    const node = new Node()\n542\t    node.insert('get', '/:id/:action{create|update}', 'foo')\n543\t    node.insert('get', '/:id/:action{delete}', 'bar')\n544\t    it('get /123/create', () => {\n545\t      const [res] = node.search('get', '/123/create')\n546\t      expect(res.length).toBe(1)\n547\t      expect(res[0][0]).toBe('foo')\n548\t      expect(res[0][1]).toEqual({ id: '123', action: 'create' })\n549\t    })\n550\t    it('get /123/delete', () => {\n551\t      const [res] = node.search('get', '/123/delete')\n552\t      expect(res.length).toBe(1)\n553\t      expect(res[0][0]).toBe('bar')\n554\t      expect(res[0][1]).toEqual({ id: '123', action: 'delete' })\n555\t    })\n556\t  })\n557\t})\n558\t\n559\tdescribe('Sort Order', () => {\n560\t  describe('Basic', () => {\n561\t    const node = new Node()\n562\t    node.insert('get', '*', 'a')\n563\t    node.insert('get', '/page', '/page')\n564\t    node.insert('get', '/:slug', '/:slug')\n565\t\n566\t    it('get /page', () => {\n567\t      const [res] = node.search('get', '/page')\n568\t      expect(res.length).toBe(3)\n569\t      expect(res[0][0]).toEqual('a')\n570\t      expect(res[1][0]).toEqual('/page')\n571\t      expect(res[2][0]).toEqual('/:slug')\n572\t    })\n573\t  })\n574\t\n575\t  describe('With Named path', () => {\n576\t    const node = new Node()\n577\t    node.insert('get', '*', 'a')\n578\t    node.insert('get', '/posts/:id', '/posts/:id')\n579\t    node.insert('get', '/:type/:id', '/:type/:id')\n580\t\n581\t    it('get /posts/123', () => {\n582\t      const [res] = node.search('get', '/posts/123')\n583\t      expect(res.length).toBe(3)\n584\t      expect(res[0][0]).toEqual('a')\n585\t      expect(res[1][0]).toEqual('/posts/:id')\n586\t      expect(res[2][0]).toEqual('/:type/:id')\n587\t    })\n588\t  })\n589\t\n590\t  describe('With Wildcards', () => {\n591\t    const node = new Node()\n592\t    node.insert('get', '/api/*', '1st')\n593\t    node.insert('get', '/api/*', '2nd')\n594\t    node.insert('get', '/api/posts/:id', '3rd')\n595\t    node.insert('get', '/api/*', '4th')\n596\t\n597\t    it('get /api/posts/123', () => {\n598\t      const [res] = node.search('get', '/api/posts/123')\n599\t      expect(res.length).toBe(4)\n600\t      expect(res[0][0]).toEqual('1st')\n601\t      expect(res[1][0]).toEqual('2nd')\n602\t      expect(res[2][0]).toEqual('3rd')\n603\t      expect(res[3][0]).toEqual('4th')\n604\t    })\n605\t  })\n606\t\n607\t  describe('With special Wildcard', () => {\n608\t    const node = new Node()\n609\t    node.insert('get', '/posts', '/posts') // 1.1\n610\t    node.insert('get', '/posts/*', '/posts/*') // 1.2\n611\t    node.insert('get', '/posts/:id', '/posts/:id') // 2.3\n612\t\n613\t    it('get /posts', () => {\n614\t      const [res] = node.search('get', '/posts')\n615\t      expect(res.length).toBe(2)\n616\t      expect(res[0][0]).toEqual('/posts')\n617\t      expect(res[1][0]).toEqual('/posts/*')\n618\t    })\n619\t  })\n620\t\n621\t  describe('Complex', () => {\n622\t    const node = new Node()\n623\t    node.insert('get', '/api', 'a') // not match\n624\t    node.insert('get', '/api/*', 'b') // match\n625\t    node.insert('get', '/api/:type', 'c') // not match\n626\t    node.insert('get', '/api/:type/:id', 'd') // match\n627\t    node.insert('get', '/api/posts/:id', 'e') // match\n628\t    node.insert('get', '/api/posts/123', 'f') // match\n629\t    node.insert('get', '/*/*/:id', 'g') // match\n630\t    node.insert('get', '/api/posts/*/comment', 'h') // not match\n631\t    node.insert('get', '*', 'i') // match\n632\t    node.insert('get', '*', 'j') // match\n633\t\n634\t    it('get /api/posts/123', () => {\n635\t      const [res] = node.search('get', '/api/posts/123')\n636\t      expect(res.length).toBe(7)\n637\t      expect(res[0][0]).toEqual('b')\n638\t      expect(res[1][0]).toEqual('d')\n639\t      expect(res[2][0]).toEqual('e')\n640\t      expect(res[3][0]).toEqual('f')\n641\t      expect(res[4][0]).toEqual('g')\n642\t      expect(res[5][0]).toEqual('i')\n643\t      expect(res[6][0]).toEqual('j')\n644\t    })\n645\t  })\n646\t\n647\t  describe('Multi match', () => {\n648\t    const node = new Node()\n649\t    node.insert('get', '*', 'GET *') // 0.1\n650\t    node.insert('get', '/abc/*', 'GET /abc/*') // 1.2\n651\t    node.insert('get', '/abc/edf', 'GET /abc/edf') // 2.3\n652\t    node.insert('get', '/abc/*/ghi/jkl', 'GET /abc/*/ghi/jkl') // 4.4\n653\t    it('get /abc/edf', () => {\n654\t      const [res] = node.search('get', '/abc/edf')\n655\t      expect(res.length).toBe(3)\n656\t      expect(res[0][0]).toEqual('GET *')\n657\t      expect(res[1][0]).toEqual('GET /abc/*')\n658\t      expect(res[2][0]).toEqual('GET /abc/edf')\n659\t    })\n660\t  })\n661\t\n662\t  describe('Multi match', () => {\n663\t    const node = new Node()\n664\t\n665\t    node.insert('get', '/api/*', 'a') // 2.1 for /api/entry\n666\t    node.insert('get', '/api/entry', 'entry') // 2.2\n667\t    node.insert('ALL', '/api/*', 'b') // 2.3 for /api/entry\n668\t\n669\t    it('get /api/entry', async () => {\n670\t      const [res] = node.search('get', '/api/entry')\n671\t      expect(res.length).toBe(3)\n672\t      expect(res[0][0]).toEqual('a')\n673\t      expect(res[1][0]).toEqual('entry')\n674\t      expect(res[2][0]).toEqual('b')\n675\t    })\n676\t  })\n677\t\n678\t  describe('fallback', () => {\n679\t    describe('Blog - failed', () => {\n680\t      const node = new Node()\n681\t      node.insert('post', '/entry', 'post entry') // 1.1\n682\t      node.insert('post', '/entry/*', 'fallback') // 1.2\n683\t      node.insert('get', '/entry/:id', 'get entry') // 2.3\n684\t      it('post /entry', async () => {\n685\t        const [res] = node.search('post', '/entry')\n686\t        expect(res.length).toBe(2)\n687\t        expect(res[0][0]).toEqual('post entry')\n688\t        expect(res[1][0]).toEqual('fallback')\n689\t      })\n690\t    })\n691\t  })\n692\t  describe('page', () => {\n693\t    const node = new Node()\n694\t    node.insert('get', '/page', 'page') // 1.1\n695\t    node.insert('ALL', '/*', 'fallback') // 1.2\n696\t    it('get /page', async () => {\n697\t      const [res] = node.search('get', '/page')\n698\t      expect(res.length).toBe(2)\n699\t      expect(res[0][0]).toEqual('page')\n700\t      expect(res[1][0]).toEqual('fallback')\n701\t    })\n702\t  })\n703\t})\n704\t\n705\tdescribe('star', () => {\n706\t  const node = new Node()\n707\t  node.insert('get', '/', '/')\n708\t  node.insert('get', '/*', '/*')\n709\t  node.insert('get', '*', '*')\n710\t\n711\t  node.insert('get', '/x', '/x')\n712\t  node.insert('get', '/x/*', '/x/*')\n713\t\n714\t  it('top', async () => {\n715\t    const [res] = node.search('get', '/')\n716\t    expect(res.length).toBe(3)\n717\t    expect(res[0][0]).toEqual('/')\n718\t    expect(res[1][0]).toEqual('/*')\n719\t    expect(res[2][0]).toEqual('*')\n720\t  })\n721\t\n722\t  it('Under a certain path', async () => {\n723\t    const [res] = node.search('get', '/x')\n724\t    expect(res.length).toBe(4)\n725\t    expect(res[0][0]).toEqual('/*')\n726\t    expect(res[1][0]).toEqual('*')\n727\t    expect(res[2][0]).toEqual('/x')\n728\t    expect(res[3][0]).toEqual('/x/*')\n729\t  })\n730\t})\n731\t\n732\tdescribe('Routing order With named parameters', () => {\n733\t  const node = new Node()\n734\t  node.insert('get', '/book/a', 'no-slug')\n735\t  node.insert('get', '/book/:slug', 'slug')\n736\t  node.insert('get', '/book/b', 'no-slug-b')\n737\t  it('/book/a', () => {\n738\t    const [res] = node.search('get', '/book/a')\n739\t    expect(res).not.toBeNull()\n740\t    expect(res.length).toBe(2)\n741\t    expect(res[0][0]).toEqual('no-slug')\n742\t    expect(res[0][1]).toEqual({})\n743\t    expect(res[1][0]).toEqual('slug')\n744\t    expect(res[1][1]).toEqual({ slug: 'a' })\n745\t  })\n746\t  it('/book/foo', () => {\n747\t    const [res] = node.search('get', '/book/foo')\n748\t    expect(res).not.toBeNull()\n749\t    expect(res.length).toBe(1)\n750\t    expect(res[0][0]).toEqual('slug')\n751\t    expect(res[0][1]).toEqual({ slug: 'foo' })\n752\t    expect(res[0][1]['slug']).toBe('foo')\n753\t  })\n754\t  it('/book/b', () => {\n755\t    const [res] = node.search('get', '/book/b')\n756\t    expect(res).not.toBeNull()\n757\t    expect(res.length).toBe(2)\n758\t    expect(res[0][0]).toEqual('slug')\n759\t    expect(res[0][1]).toEqual({ slug: 'b' })\n760\t    expect(res[1][0]).toEqual('no-slug-b')\n761\t    expect(res[1][1]).toEqual({})\n762\t  })\n763\t})\n764\t\n765\tdescribe('The same name is used for path params', () => {\n766\t  describe('Basic', () => {\n767\t    const node = new Node()\n768\t    node.insert('get', '/:a/:b/:c', 'abc')\n769\t    node.insert('get', '/:a/:b/:c/:d', 'abcd')\n770\t    it('/1/2/3', () => {\n771\t      const [res] = node.search('get', '/1/2/3')\n772\t      expect(res).not.toBeNull()\n773\t      expect(res.length).toBe(1)\n774\t      expect(res[0][0]).toEqual('abc')\n775\t      expect(res[0][1]).toEqual({ a: '1', b: '2', c: '3' })\n776\t    })\n777\t  })\n778\t\n779\t  describe('Complex', () => {\n780\t    const node = new Node()\n781\t    node.insert('get', '/:a', 'a')\n782\t    node.insert('get', '/:b/:a', 'ba')\n783\t    it('/about/me', () => {\n784\t      const [res] = node.search('get', '/about/me')\n785\t      expect(res).not.toBeNull()\n786\t      expect(res.length).toBe(1)\n787\t      expect(res[0][0]).toEqual('ba')\n788\t      expect(res[0][1]).toEqual({ b: 'about', a: 'me' })\n789\t    })\n790\t  })\n791\t\n792\t  describe('Complex with tails', () => {\n793\t    const node = new Node()\n794\t    node.insert('get', '/:id/:id2/comments', 'a')\n795\t    node.insert('get', '/posts/:id/comments', 'b')\n796\t    it('/posts/123/comments', () => {\n797\t      const [res] = node.search('get', '/posts/123/comments')\n798\t      expect(res).not.toBeNull()\n799\t      expect(res.length).toBe(2)\n800\t      expect(res[0][0]).toEqual('a')\n801\t      expect(res[0][1]).toEqual({ id: 'posts', id2: '123' })\n802\t      expect(res[1][0]).toEqual('b')\n803\t      expect(res[1][1]).toEqual({ id: '123' })\n804\t    })\n805\t  })\n806\t})\n807\t\n808\tdescribe('Node with initial method and handler', () => {\n809\t  it('should create a node with method and handler via constructor', () => {\n810\t    const node = new Node('get', 'initial handler')\n811\t    node.insert('get', '/hello', 'hello handler')\n812\t    const [res] = node.search('get', '/hello')\n813\t    expect(res.length).toBe(1)\n814\t    expect(res[0][0]).toEqual('hello handler')\n815\t  })\n816\t})\n817\t"}]},"parent_tool_use_id":null,"session_id":"d8e93c8f-249f-44a6-a724-453f92d92997","uuid":"a702758f-adc5-4726-8b18-24affb623b99","timestamp":"2026-07-20T20:19:48.987Z","tool_use_result":{"type":"text","file":{"filePath":"/private/tmp/tokenwarden-bench/claude-code/2026-07-20T20-12-48-884Z/baseline-routing-read-write-ledger-1/repo/src/router/trie-router/node.test.ts","content":"import { Node } from './node'\n\ndescribe('Root Node', () => {\n  const node = new Node()\n  node.insert('get', '/', 'get root')\n  it('get /', () => {\n    const [res] = node.search('get', '/')\n    expect(res).not.toBeNull()\n    expect(res[0][0]).toEqual('get root')\n    expect(node.search('get', '/hello')[0].length).toBe(0)\n  })\n})\n\ndescribe('Root Node is not defined', () => {\n  const node = new Node()\n  node.insert('get', '/hello', 'get hello')\n  it('get /', () => {\n    expect(node.search('get', '/')[0]).toEqual([])\n  })\n})\n\ndescribe('Get with *', () => {\n  const node = new Node()\n  node.insert('get', '*', 'get all')\n  it('get /', () => {\n    expect(node.search('get', '/')[0].length).toBe(1)\n    expect(node.search('get', '/hello')[0].length).toBe(1)\n  })\n})\n\ndescribe('Get with * including JS reserved words', () => {\n  const node = new Node()\n  node.insert('get', '*', 'get all')\n  it('get /', () => {\n    expect(node.search('get', '/hello/constructor')[0].length).toBe(1)\n    expect(node.search('get', '/hello/__proto__')[0].length).toBe(1)\n  })\n})\n\ndescribe('Basic Usage', () => {\n  const node = new Node()\n  node.insert('get', '/hello', 'get hello')\n  node.insert('post', '/hello', 'post hello')\n  node.insert('get', '/hello/foo', 'get hello foo')\n\n  it('get, post /hello', () => {\n    expect(node.search('get', '/')[0].length).toBe(0)\n    expect(node.search('post', '/')[0].length).toBe(0)\n\n    expect(node.search('get', '/hello')[0][0][0]).toEqual('get hello')\n    expect(node.search('post', '/hello')[0][0][0]).toEqual('post hello')\n    expect(node.search('put', '/hello')[0].length).toBe(0)\n  })\n  it('get /nothing', () => {\n    expect(node.search('get', '/nothing')[0].length).toBe(0)\n  })\n  it('/hello/foo, /hello/bar', () => {\n    expect(node.search('get', '/hello/foo')[0][0][0]).toEqual('get hello foo')\n    expect(node.search('post', '/hello/foo')[0].length).toBe(0)\n    expect(node.search('get', '/hello/bar')[0].length).toBe(0)\n  })\n  it('/hello/foo/bar', () => {\n    expect(node.search('get', '/hello/foo/bar')[0].length).toBe(0)\n  })\n})\n\ndescribe('Name path', () => {\n  const node = new Node()\n  node.insert('get', '/entry/:id', 'get entry')\n  node.insert('get', '/entry/:id/comment/:comment_id', 'get comment')\n  node.insert('get', '/map/:location/events', 'get events')\n  node.insert('get', '/about/:name/address/map', 'get address')\n\n  it('get /entry/123', () => {\n    const [res] = node.search('get', '/entry/123')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('get entry')\n    expect(res[0][1]).not.toBeNull()\n    expect(res[0][1]['id']).toBe('123')\n    expect(res[0][1]['id']).not.toBe('1234')\n  })\n\n  it('get /entry/456/comment', () => {\n    const [res] = node.search('get', '/entry/456/comment')\n    expect(res.length).toBe(0)\n  })\n\n  it('get /entry/789/comment/123', () => {\n    const [res] = node.search('get', '/entry/789/comment/123')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('get comment')\n    expect(res[0][1]['id']).toBe('789')\n    expect(res[0][1]['comment_id']).toBe('123')\n  })\n\n  it('get /map/:location/events', () => {\n    const [res] = node.search('get', '/map/yokohama/events')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('get events')\n    expect(res[0][1]['location']).toBe('yokohama')\n  })\n\n  it('get /about/:name/address/map', () => {\n    const [res] = node.search('get', '/about/foo/address/map')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('get address')\n    expect(res[0][1]['name']).toBe('foo')\n  })\n\n  it('Should not return a previous param value', () => {\n    const node = new Node()\n    node.insert('delete', '/resource/:id', 'resource')\n    const [resA] = node.search('delete', '/resource/a')\n    const [resB] = node.search('delete', '/resource/b')\n    expect(resA).not.toBeNull()\n    expect(resA.length).toBe(1)\n    expect(resA[0][0]).toEqual('resource')\n    expect(resA[0][1]).toEqual({ id: 'a' })\n    expect(resB).not.toBeNull()\n    expect(resB.length).toBe(1)\n    expect(resB[0][0]).toEqual('resource')\n    expect(resB[0][1]).toEqual({ id: 'b' })\n  })\n\n  it('Should return a sorted values', () => {\n    const node = new Node()\n    node.insert('get', '/resource/a', 'A')\n    node.insert('get', '/resource/*', 'Star')\n    const [res] = node.search('get', '/resource/a')\n    expect(res).not.toBeNull()\n    expect(res.length).toBe(2)\n    expect(res[0][0]).toEqual('A')\n    expect(res[1][0]).toEqual('Star')\n  })\n})\n\ndescribe('Name path - Multiple route', () => {\n  const node = new Node()\n\n  node.insert('get', '/:type/:id', 'common')\n  node.insert('get', '/posts/:id', 'specialized')\n\n  it('get /posts/123', () => {\n    const [res] = node.search('get', '/posts/123')\n    expect(res.length).toBe(2)\n    expect(res[0][0]).toEqual('common')\n    expect(res[0][1]['id']).toBe('123')\n    expect(res[1][0]).toEqual('specialized')\n    expect(res[1][1]['id']).toBe('123')\n  })\n})\n\ndescribe('Param prefix', () => {\n  const node = new Node()\n\n  node.insert('get', '/:foo', 'onepart')\n  node.insert('get', '/:bar/:baz', 'twopart')\n\n  it('get /hello', () => {\n    const [res] = node.search('get', '/hello')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('onepart')\n    expect(res[0][1]['foo']).toBe('hello')\n  })\n\n  it('get /hello/world', () => {\n    const [res] = node.search('get', '/hello/world')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('twopart')\n    expect(res[0][1]['bar']).toBe('hello')\n    expect(res[0][1]['baz']).toBe('world')\n  })\n})\n\ndescribe('Named params and a wildcard', () => {\n  const node = new Node()\n\n  node.insert('get', '/:id/*', 'onepart')\n\n  it('get /', () => {\n    const [res] = node.search('get', '/')\n    expect(res.length).toBe(0)\n  })\n\n  it('get /foo', () => {\n    const [res] = node.search('get', '/foo')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('onepart')\n    expect(res[0][1]['id']).toEqual('foo')\n  })\n\n  it('get /foo/bar', () => {\n    const [res] = node.search('get', '/foo/bar')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('onepart')\n    expect(res[0][1]['id']).toEqual('foo')\n  })\n})\n\ndescribe('Wildcard', () => {\n  const node = new Node()\n  node.insert('get', '/wildcard-abc/*/wildcard-efg', 'wildcard')\n  it('/wildcard-abc/xxxxxx/wildcard-efg', () => {\n    const [res] = node.search('get', '/wildcard-abc/xxxxxx/wildcard-efg')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('wildcard')\n  })\n  node.insert('get', '/wildcard-abc/*/wildcard-efg/hijk', 'wildcard')\n  it('/wildcard-abc/xxxxxx/wildcard-efg/hijk', () => {\n    const [res] = node.search('get', '/wildcard-abc/xxxxxx/wildcard-efg/hijk')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('wildcard')\n  })\n})\n\ndescribe('Regexp', () => {\n  const node = new Node()\n  node.insert('get', '/regex-abc/:id{[0-9]+}/comment/:comment_id{[a-z]+}', 'regexp')\n  it('/regexp-abc/123/comment/abc', () => {\n    const [res] = node.search('get', '/regex-abc/123/comment/abc')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('regexp')\n    expect(res[0][1]['id']).toBe('123')\n    expect(res[0][1]['comment_id']).toBe('abc')\n  })\n  it('/regexp-abc/abc', () => {\n    const [res] = node.search('get', '/regex-abc/abc')\n    expect(res.length).toBe(0)\n  })\n  it('/regexp-abc/123/comment/123', () => {\n    const [res] = node.search('get', '/regex-abc/123/comment/123')\n    expect(res.length).toBe(0)\n  })\n})\n\ndescribe('All', () => {\n  const node = new Node()\n  node.insert('ALL', '/all-methods', 'all methods') // ALL\n  it('/all-methods', () => {\n    let [res] = node.search('get', '/all-methods')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('all methods')\n    ;[res] = node.search('put', '/all-methods')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('all methods')\n  })\n})\n\ndescribe('Special Wildcard', () => {\n  const node = new Node()\n  node.insert('ALL', '*', 'match all')\n\n  it('/foo', () => {\n    const [res] = node.search('get', '/foo')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('match all')\n  })\n  it('/hello', () => {\n    const [res] = node.search('get', '/hello')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('match all')\n  })\n  it('/hello/foo', () => {\n    const [res] = node.search('get', '/hello/foo')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('match all')\n  })\n})\n\ndescribe('Special Wildcard deeply', () => {\n  const node = new Node()\n  node.insert('ALL', '/hello/*', 'match hello')\n  it('/hello', () => {\n    const [res] = node.search('get', '/hello')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('match hello')\n  })\n  it('/hello/foo', () => {\n    const [res] = node.search('get', '/hello/foo')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('match hello')\n  })\n})\n\ndescribe('Default with wildcard', () => {\n  const node = new Node()\n  node.insert('ALL', '/api/*', 'fallback')\n  node.insert('ALL', '/api/abc', 'match api')\n  it('/api/abc', () => {\n    const [res] = node.search('get', '/api/abc')\n    expect(res.length).toBe(2)\n    expect(res[0][0]).toEqual('fallback')\n    expect(res[1][0]).toEqual('match api')\n  })\n  it('/api/def', () => {\n    const [res] = node.search('get', '/api/def')\n    expect(res.length).toBe(1)\n    expect(res[0][0]).toEqual('fallback')\n  })\n})\n\ndescribe('Multi match', () => {\n  describe('Basic', () => {\n    const node = new Node()\n    node.insert('get', '*', 'GET *')\n    node.insert('get', '/abc/*', 'GET /abc/*')\n    node.insert('get', '/abc/*/edf', 'GET /abc/*/edf')\n    node.insert('get', '/abc/edf', 'GET /abc/edf')\n    node.insert('get', '/abc/*/ghi/jkl', 'GET /abc/*/ghi/jkl')\n    it('get /abc/edf', () => {\n      const [res] = node.search('get', '/abc/edf')\n      expect(res.length).toBe(3)\n      expect(res[0][0]).toEqual('GET *')\n      expect(res[1][0]).toEqual('GET /abc/*')\n      expect(res[2][0]).toEqual('GET /abc/edf')\n    })\n    it('get /abc/xxx/edf', () => {\n      const [res] = node.search('get', '/abc/xxx/edf')\n      expect(res.length).toBe(3)\n      expect(res[0][0]).toEqual('GET *')\n      expect(res[1][0]).toEqual('GET /abc/*')\n      expect(res[2][0]).toEqual('GET /abc/*/edf')\n    })\n    it('get /', () => {\n      const [res] = node.search('get', '/')\n      expect(res.length).toBe(1)\n      expect(res[0][0]).toEqual('GET *')\n    })\n    it('post /', () => {\n      const [res] = node.search('post', '/')\n      expect(res.length).toBe(0)\n    })\n    it('get /abc/edf/ghi', () => {\n      const [res] = node.search('get', '/abc/edf/ghi')\n      expect(res.length).toBe(2)\n      expect(res[0][0]).toEqual('GET *')\n      expect(res[1][0]).toEqual('GET /abc/*')\n    })\n  })\n  describe('Blog', () => {\n    const node = new Node()\n    node.insert('get', '*', 'middleware a') // 0.1\n    node.insert('ALL', '*', 'middleware b') // 0.2 <===\n    node.insert('get', '/entry', 'get entries') // 1.3\n    node.insert('post', '/entry/*', 'middleware c') // 1.4 <===\n    node.insert('post', '/entry', 'post entry') // 1.5 <===\n    node.insert('get', '/entry/:id', 'get entry') // 2.6\n    node.insert('get', '/entry/:id/comment/:comment_id', 'get comment') // 4.7\n    it('get /entry/123', async () => {\n      const [res] = node.search('get', '/entry/123')\n      expect(res.length).toBe(3)\n      expect(res[0][0]).toEqual('middleware a')\n      expect(res[0][1]['id']).toBe(undefined)\n      expect(res[1][0]).toEqual('middleware b')\n      expect(res[1][1]['id']).toBe(undefined)\n      expect(res[2][0]).toEqual('get entry')\n      expect(res[2][1]['id']).toBe('123')\n    })\n    it('get /entry/123/comment/456', async () => {\n      const [res] = node.search('get', '/entry/123/comment/456')\n      expect(res.length).toBe(3)\n      expect(res[0][0]).toEqual('middleware a')\n      expect(res[0][1]['id']).toBe(undefined)\n      expect(res[0][1]['comment_id']).toBe(undefined)\n      expect(res[1][0]).toEqual('middleware b')\n      expect(res[1][1]['id']).toBe(undefined)\n      expect(res[1][1]['comment_id']).toBe(undefined)\n      expect(res[2][0]).toEqual('get comment')\n      expect(res[2][1]['id']).toBe('123')\n      expect(res[2][1]['comment_id']).toBe('456')\n    })\n    it('post /entry', async () => {\n      const [res] = node.search('post', '/entry')\n      expect(res.length).toBe(3)\n      expect(res[0][0]).toEqual('middleware b')\n      expect(res[1][0]).toEqual('middleware c')\n      expect(res[2][0]).toEqual('post entry')\n    })\n    it('delete /entry', async () => {\n      const [res] = node.search('delete', '/entry')\n      expect(res.length).toBe(1)\n      expect(res[0][0]).toEqual('middleware b')\n    })\n  })\n  describe('ALL', () => {\n    const node = new Node()\n    node.insert('ALL', '*', 'ALL *')\n    node.insert('ALL', '/abc/*', 'ALL /abc/*')\n    node.insert('ALL', '/abc/*/def', 'ALL /abc/*/def')\n    it('get /', () => {\n      const [res] = node.search('get', '/')\n      expect(res.length).toBe(1)\n      expect(res[0][0]).toEqual('ALL *')\n    })\n    it('post /abc', () => {\n      const [res] = node.search('post', '/abc')\n      expect(res.length).toBe(2)\n      expect(res[0][0]).toEqual('ALL *')\n      expect(res[1][0]).toEqual('ALL /abc/*')\n    })\n    it('delete /abc/xxx/def', () => {\n      const [res] = node.search('post', '/abc/xxx/def')\n      expect(res.length).toBe(3)\n      expect(res[0][0]).toEqual('ALL *')\n      expect(res[1][0]).toEqual('ALL /abc/*')\n      expect(res[2][0]).toEqual('ALL /abc/*/def')\n    })\n  })\n  des